mapper.select:
SELECT awr.*, sis.id as sis_id, sis.student_id as sis_student_id, sis.status as sis_status, sis.company_id as sis_company_id, sis.position_id as sis_position_id, su.id as su_id, su.name as su_name, su.student_user_id as su_student_user_id, su.gender as su_gender, su.grade as su_grade, su.major_id as su_major_id, su.class_id as su_class_id, cu.id as cu_id, cu.company_name as cu_company_name, cu.contact_person as cu_contact_person, cu.contact_phone as cu_contact_phone, cu.contact_email as cu_contact_email, p.id as p_id, p.position_name as p_position_name, p.company_id as p_company_id FROM application_withdrawal_records awr LEFT JOIN student_internship_status sis ON awr.status_id = sis.id LEFT JOIN student_users su ON sis.student_id = su.id LEFT JOIN company_users cu ON sis.company_id = cu.id LEFT JOIN position p ON sis.position_id = p.id
AND awr.status_id = #{statusId}
AND awr.applicant_id = #{applicantId}
AND awr.applicant_role = #{applicantRole}
ORDER BY awr.withdrawal_time DESC

SELECT awr.*, sis.id as sis_id, sis.student_id as sis_student_id, sis.status as sis_status, sis.company_id as sis_company_id, sis.position_id as sis_position_id, su.id as su_id, su.name as su_name, su.student_user_id as su_student_user_id, su.gender as su_gender, su.grade as su_grade, su.major_id as su_major_id, su.class_id as su_class_id, cu.id as cu_id, cu.company_name as cu_company_name, cu.contact_person as cu_contact_person, cu.contact_phone as cu_contact_phone, cu.contact_email as cu_contact_email, p.id as p_id, p.position_name as p_position_name, p.company_id as p_company_id FROM application_withdrawal_records awr LEFT JOIN student_internship_status sis ON awr.status_id = sis.id LEFT JOIN student_users su ON sis.student_id = su.id LEFT JOIN company_users cu ON sis.company_id = cu.id LEFT JOIN position p ON sis.position_id = p.id
AND awr.status_id = #{statusId}
AND awr.applicant_id = #{applicantId}
AND awr.applicant_role = #{applicantRole}
AND su.name LIKE CONCAT('%', #{applicantName}, '%')
AND awr.withdrawal_time >= #{startTime}
AND awr.withdrawal_time <= CONCAT(#{endTime}, ' 23:59:59')
ORDER BY awr.withdrawal_time DESC

SELECT * FROM application_withdrawal_records WHERE id IN
#{id}
ORDER BY withdrawal_time DESC
